const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('packages') || '[]');
const sections = JSON.parse(localStorage.getItem('package_menu_sections') || '[]');
const menuItems = JSON.parse(localStorage.getItem('package_menu_items') || '[]');
const dishes = JSON.parse(localStorage.getItem('dishes') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

if (!Array.isArray(carts) || carts.length === 0) {
  return 0;
}
const cart = carts[0];
const itemsForCart = cartItems.filter(ci => ci.cartId === cart.id);

function getPackage(pkgId) {
  return packages.find(p => p.id === pkgId) || null;
}

function countVegetarianDishesForCartItem(ci, pkg) {
  const pkgSections = sections.filter(s => s.packageId === pkg.id);
  const sectionIds = pkgSections.map(s => s.id);
  const pkgMenuItems = menuItems.filter(mi => sectionIds.indexOf(mi.packageMenuSectionId) !== -1);
  const validDishIds = new Set(pkgMenuItems.map(mi => mi.dishId));

  const selectedIds = Array.isArray(ci.selectedDishIds) ? ci.selectedDishIds : [];
  let vegCount = 0;
  for (let i = 0; i < selectedIds.length; i++) {
    const did = selectedIds[i];
    if (!validDishIds.has(did)) continue;
    const dish = dishes.find(d => d.id === did);
    if (dish && dish.isVegetarian === true) {
      vegCount++;
    }
  }
  return vegCount;
}

// Identify corporate lunch buffet items with correct config
const qualifyingItems = [];
const corporateLunchItems = [];

for (let i = 0; i < itemsForCart.length; i++) {
  const ci = itemsForCart[i];
  if (ci.itemType !== 'package') continue;
  const pkg = getPackage(ci.packageId);
  if (!pkg) continue;
  if (pkg.categoryCode === 'corporate_events' && pkg.mealType === 'lunch' && pkg.serviceStyle === 'buffet' && pkg.allowsMenuCustomization === true) {
    corporateLunchItems.push({ ci, pkg });
    if (ci.guestCount === 25 && typeof ci.perPersonPrice === 'number' && ci.perPersonPrice <= 25) {
      const vegCount = countVegetarianDishesForCartItem(ci, pkg);
      if (vegCount >= 3) {
        qualifyingItems.push({ ci, pkg });
      }
    }
  }
}

// CP1 (0.7): At least one cart item is a customizable corporate lunch buffet for 25 guests, <=$25/pp, with >=3 vegetarian dishes
const cp1Passed = qualifyingItems.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.7 });

// CP2 (0.3): Exactly one corporate lunch buffet package line in the cart and it qualifies
const cp2Passed = cp1Passed && corporateLunchItems.length === 1 && qualifyingItems.length === 1;
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('packages') || '[]');
const addOns = JSON.parse(localStorage.getItem('add_ons') || '[]');
const quoteRequests = JSON.parse(localStorage.getItem('quote_requests') || '[]');

if (!Array.isArray(quoteRequests) || quoteRequests.length === 0) {
  return 0;
}

// All 3-course plated wedding dinner packages
const weddingPkgs = packages.filter(p => p.categoryCode === 'weddings' && p.mealType === 'dinner' && p.serviceStyle === 'plated' && typeof p.courseCount === 'number' && p.courseCount === 3);

if (weddingPkgs.length === 0) {
  return 0;
}

const prices = weddingPkgs.map(p => (typeof p.basePricePerPerson === 'number' ? p.basePricePerPerson : (typeof p.minPricePerPerson === 'number' ? p.minPricePerPerson : 0)));
const minPrice = Math.min.apply(null, prices);
const maxPrice = Math.max.apply(null, prices);

function isMidPriced(pkg) {
  const price = typeof pkg.basePricePerPerson === 'number' ? pkg.basePricePerPerson : (typeof pkg.minPricePerPerson === 'number' ? pkg.minPricePerPerson : 0);
  return price > minPrice && price < maxPrice; // neither cheapest nor most expensive
}

const now = new Date();

const qualifying = [];
for (let i = 0; i < quoteRequests.length; i++) {
  const qr = quoteRequests[i];
  if (qr.guestCount !== 120) continue;
  const pkg = packages.find(p => p.id === qr.packageId);
  if (!pkg) continue;
  if (!(pkg.categoryCode === 'weddings' && pkg.mealType === 'dinner' && pkg.serviceStyle === 'plated' && pkg.courseCount === 3)) continue;

  const selectedAddonIds = Array.isArray(qr.selectedAddonIds) ? qr.selectedAddonIds : [];
  const qrAddOns = addOns.filter(a => selectedAddonIds.indexOf(a.id) !== -1);
  const hasPerPersonBar = qrAddOns.some(a => a.category === 'bar_service' && a.priceType === 'per_person' && a.isPaid !== false);
  if (!hasPerPersonBar) continue;

  if (!qr.eventDate) continue;
  const eventDate = new Date(qr.eventDate);
  if (!(eventDate > now)) continue;

  if (!qr.contactName || !qr.contactEmail) continue;

  qualifying.push({ qr, pkg });
}

// CP1 (0.5): Submitted quote for 120 guests with a 3-course plated wedding package, per-person bar add-on, future date, and contact info
const cp1Passed = qualifying.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.5 });

// CP2 (0.5): At least one such quote uses a mid-priced package (neither cheapest nor most expensive among 3-course plated weddings)
let cp2Passed = false;
if (cp1Passed) {
  cp2Passed = qualifying.some(q => isMidPriced(q.pkg));
}
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const comparedIds = JSON.parse(localStorage.getItem('task3_comparedPackageIds') || '[]');
const packages = JSON.parse(localStorage.getItem('packages') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

if (!Array.isArray(carts) || carts.length === 0) {
  return 0;
}
const cart = carts[0];

const comparedPkgs = packages.filter(p => Array.isArray(comparedIds) && comparedIds.indexOf(p.id) !== -1);

// Birthday/party packages including dessert and serving 40 guests
const qualifyingCompared = comparedPkgs.filter(p => {
  if (p.categoryCode !== 'parties_birthdays') return false;
  if (p.includesDessert !== true) return false;
  if (typeof p.minGuests !== 'number' || typeof p.maxGuests !== 'number') return false;
  return p.minGuests <= 40 && p.maxGuests >= 40;
});

// CP1 (0.4): At least two compared packages are valid birthday/party options with dessert for 40 guests
const cp1Passed = qualifyingCompared.length >= 2;
checkpoints.push({ passed: cp1Passed, weight: 0.4 });

function perPerson(p) {
  if (typeof p.basePricePerPerson === 'number') return p.basePricePerPerson;
  if (typeof p.minPricePerPerson === 'number') return p.minPricePerPerson;
  return 0;
}

const comparedWithTotals = qualifyingCompared.map(p => ({ pkg: p, total: perPerson(p) * 40 }));
let minTotal = null;
let cheapestPkgIds = [];
for (let i = 0; i < comparedWithTotals.length; i++) {
  const obj = comparedWithTotals[i];
  if (minTotal === null || obj.total < minTotal) {
    minTotal = obj.total;
    cheapestPkgIds = [obj.pkg.id];
  } else if (obj.total === minTotal) {
    cheapestPkgIds.push(obj.pkg.id);
  }
}

const itemsForCart = cartItems.filter(ci => ci.cartId === cart.id);

// Birthday/party cart items for 40 guests with dessert
const partyItemsFor40 = itemsForCart.filter(ci => {
  if (ci.itemType !== 'package' || ci.guestCount !== 40) return false;
  const pkg = packages.find(p => p.id === ci.packageId);
  if (!pkg) return false;
  if (pkg.categoryCode !== 'parties_birthdays') return false;
  if (pkg.includesDessert !== true) return false;
  if (typeof pkg.minGuests !== 'number' || typeof pkg.maxGuests !== 'number') return false;
  return pkg.minGuests <= 40 && pkg.maxGuests >= 40;
});

// Items that are the cheapest among the compared qualifying packages
const correctCartItems = partyItemsFor40.filter(ci => {
  const pkg = packages.find(p => p.id === ci.packageId);
  if (!pkg) return false;
  if (cheapestPkgIds.indexOf(pkg.id) === -1) return false;
  if (!qualifyingCompared.find(p => p.id === pkg.id)) return false; // must be one of the compared qualifying packages
  const expectedTotal = perPerson(pkg) * 40;
  const lineSubtotal = typeof ci.lineSubtotal === 'number' ? ci.lineSubtotal : 0;
  return Math.abs(lineSubtotal - expectedTotal) < 0.01;
});

// CP2 (0.6): Exactly one qualifying birthday package for 40 guests is in the cart, and it is the cheapest among the compared qualifying options
const cp2Passed = cp1Passed && partyItemsFor40.length === 1 && correctCartItems.length === 1;
checkpoints.push({ passed: cp2Passed, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const customMenus = JSON.parse(localStorage.getItem('custom_menus') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');

// Identify qualifying custom dinner menus
const qualifyingMenus = customMenus.filter(cm => {
  if (cm.mealType !== 'dinner') return false;
  const gc = typeof cm.guestCount === 'number' ? cm.guestCount : 0;
  if (gc < 20 || gc > 30) return false;
  if (typeof cm.pricePerPerson !== 'number' || cm.pricePerPerson > 55) return false;
  const appCount = Array.isArray(cm.selectedAppetizerIds) ? cm.selectedAppetizerIds.length : 0;
  const mainCount = Array.isArray(cm.selectedMainIds) ? cm.selectedMainIds.length : 0;
  const desCount = Array.isArray(cm.selectedDessertIds) ? cm.selectedDessertIds.length : 0;
  if (appCount < 2 || mainCount < 2 || desCount < 1) return false;
  return true;
});

// CP1 (0.6): A custom dinner menu exists with 2+ appetizers, 2+ mains, 1+ dessert, <=$55/pp, and 20–30 guests
const cp1Passed = qualifyingMenus.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.6 });

// CP2 (0.4): At least one such custom menu has been added to the cart (appears as a custom_menu cart item)
let cp2Passed = false;
if (cp1Passed && Array.isArray(carts) && carts.length > 0) {
  const cart = carts[0];
  const itemsForCart = cartItems.filter(ci => ci.cartId === cart.id && ci.itemType === 'custom_menu');
  cp2Passed = itemsForCart.some(ci => qualifyingMenus.some(cm => cm.id === ci.customMenuId));
}
checkpoints.push({ passed: cp2Passed, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const slots = JSON.parse(localStorage.getItem('availability_slots') || '[]');
const bookings = JSON.parse(localStorage.getItem('bookings') || '[]');

// Find earliest available Saturday evening slot in July 2025
const julySlots = slots.filter(s => {
  if (!s.date) return false;
  const d = new Date(s.date);
  const year = d.getUTCFullYear();
  const month = d.getUTCMonth() + 1; // 1-12
  const weekday = d.getUTCDay(); // 0=Sun..6=Sat
  return year === 2025 && month === 7 && weekday === 6 && s.period === 'evening' && s.isAvailable === true;
});

if (julySlots.length === 0) {
  return 0;
}

julySlots.sort((a, b) => new Date(a.date) - new Date(b.date));
const earliestSlot = julySlots[0];

// Bookings for this slot with enough guests and submitted details (pending_review)
const bookingsForSlot = bookings.filter(b => b.availabilitySlotId === earliestSlot.id && b.status === 'pending_review' && typeof b.guestCount === 'number' && b.guestCount >= 80);

// CP1 (0.7): A booking exists for the earliest available Saturday evening in July 2025 with >=80 guests and status pending_review
const cp1Passed = bookingsForSlot.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.7 });

// CP2 (0.3): That booking has event name/type and contact details filled in
let cp2Passed = false;
if (cp1Passed) {
  cp2Passed = bookingsForSlot.some(b => b.eventName && b.eventType && b.contactName && b.contactPhone);
}
checkpoints.push({ passed: cp2Passed, weight: 0.3 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('packages') || '[]');
const addOns = JSON.parse(localStorage.getItem('add_ons') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const promoCodes = JSON.parse(localStorage.getItem('promo_codes') || '[]');

if (!Array.isArray(carts) || carts.length === 0) {
  return 0;
}
const cart = carts[0];
const itemsForCart = cartItems.filter(ci => ci.cartId === cart.id);

function getPackage(pkgId) {
  return packages.find(p => p.id === pkgId) || null;
}

// Find package cart items for 60 guests with base price <= 50 and exactly two paid add-ons
const qualifyingItems = itemsForCart.filter(ci => {
  if (ci.itemType !== 'package') return false;
  if (ci.guestCount !== 60) return false;
  const pkg = getPackage(ci.packageId);
  if (!pkg) return false;
  const basePrice = typeof pkg.basePricePerPerson === 'number' ? pkg.basePricePerPerson : (typeof pkg.minPricePerPerson === 'number' ? pkg.minPricePerPerson : 0);
  if (basePrice > 50) return false;
  const selectedAddonIds = Array.isArray(ci.selectedAddonIds) ? ci.selectedAddonIds : [];
  if (selectedAddonIds.length !== 2) return false;
  const addonsForItem = addOns.filter(a => selectedAddonIds.indexOf(a.id) !== -1);
  if (addonsForItem.length !== 2) return false;
  const allPaid = addonsForItem.every(a => a.isPaid !== false);
  return allPaid;
});

// CP1 (0.5): At least one qualifying 60-guest package with base<=50 and exactly two paid add-ons is in the cart
const cp1Passed = qualifyingItems.length > 0;
checkpoints.push({ passed: cp1Passed, weight: 0.5 });

// CP2 (0.5): For such an order, a 15% active promo code is applied and totalAfterDiscount < 2600
const appliedCode = (cart.appliedPromoCode || '').toLowerCase();
const promo = promoCodes.find(p => (p.code || '').toLowerCase() === appliedCode) || null;
const cp2Passed = cp1Passed && promo && promo.isActive !== false && promo.discountType === 'percentage' && promo.discountValue === 15 && typeof cart.totalAfterDiscount === 'number' && cart.totalAfterDiscount < 2600;
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const tastingLists = JSON.parse(localStorage.getItem('tasting_lists') || '[]');
const tastingItems = JSON.parse(localStorage.getItem('tasting_list_items') || '[]');
const dishes = JSON.parse(localStorage.getItem('dishes') || '[]');

if (!Array.isArray(tastingLists) || tastingLists.length === 0 || !Array.isArray(tastingItems) || tastingItems.length === 0) {
  return 0;
}

function getDish(did) {
  return dishes.find(d => d.id === did) || null;
}

let hasTwoSavoryList = false;
let hasFullCompositionList = false;

for (let i = 0; i < tastingLists.length; i++) {
  const list = tastingLists[i];
  const itemsForList = tastingItems.filter(li => li.tastingListId === list.id);
  if (itemsForList.length === 0) continue;

  const savoryIds = new Set();
  const dessertIds = new Set();

  for (let j = 0; j < itemsForList.length; j++) {
    const dish = getDish(itemsForList[j].dishId);
    if (!dish) continue;
    if (dish.isGlutenFree !== true) continue;
    if (typeof dish.rating === 'number' && dish.rating < 4) continue;

    if (dish.dishType === 'dessert') {
      dessertIds.add(dish.id);
    } else if (dish.isSavory === true) {
      savoryIds.add(dish.id);
    }
  }

  const savoryCount = savoryIds.size;
  const dessertCount = dessertIds.size;
  const totalQualifying = savoryCount + dessertCount;

  if (savoryCount >= 2) {
    hasTwoSavoryList = true;
  }
  if (savoryCount >= 2 && dessertCount >= 1 && totalQualifying >= 3) {
    hasFullCompositionList = true;
  }
}

// CP1 (0.4): Some tasting/favorites list contains at least two unique savory gluten-free dishes rated 4+ stars
checkpoints.push({ passed: hasTwoSavoryList, weight: 0.4 });

// CP2 (0.6): A single list contains at least two savory and one dessert, all gluten-free and rated 4+, with at least three unique qualifying items total
checkpoints.push({ passed: hasFullCompositionList, weight: 0.6 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

const packages = JSON.parse(localStorage.getItem('packages') || '[]');
const carts = JSON.parse(localStorage.getItem('cart') || '[]');
const cartItems = JSON.parse(localStorage.getItem('cart_items') || '[]');
const slots = JSON.parse(localStorage.getItem('availability_slots') || '[]');

if (!Array.isArray(carts) || carts.length === 0) {
  return 0;
}
const cart = carts[0];
const itemsForCart = cartItems.filter(ci => ci.cartId === cart.id && ci.itemType === 'package');

function getPackage(pkgId) {
  return packages.find(p => p.id === pkgId) || null;
}

function dateOnlyKey(dateStr) {
  const d = new Date(dateStr);
  const y = d.getUTCFullYear();
  const m = String(d.getUTCMonth() + 1).padStart(2, '0');
  const day = String(d.getUTCDate()).padStart(2, '0');
  return y + '-' + m + '-' + day;
}

// Coffee break items for 50 guests in May 2025 with an eventDate
const coffeeItems = itemsForCart.filter(ci => {
  const pkg = getPackage(ci.packageId);
  if (!pkg) return false;
  if (pkg.categoryCode !== 'coffee_breaks') return false;
  if (pkg.mealType !== 'coffee_break') return false;
  if (ci.guestCount !== 50) return false;
  if (!ci.eventDate) return false;
  const d = new Date(ci.eventDate);
  const year = d.getUTCFullYear();
  const month = d.getUTCMonth() + 1;
  if (year !== 2025 || month !== 5) return false;
  return true;
});

const dateMap = {};
for (let i = 0; i < coffeeItems.length; i++) {
  const key = dateOnlyKey(coffeeItems[i].eventDate);
  if (!dateMap[key]) {
    dateMap[key] = [];
  }
  dateMap[key].push(coffeeItems[i]);
}
const distinctDates = Object.keys(dateMap).sort();

// CP1 (0.5): Coffee-break packages for 50 guests are scheduled on at least three distinct May 2025 dates
const cp1Passed = distinctDates.length >= 3;
checkpoints.push({ passed: cp1Passed, weight: 0.5 });

// CP2 (0.5): Three earliest such dates are consecutive and each has an available morning slot
let cp2Passed = false;
if (distinctDates.length >= 3) {
  const d1 = new Date(distinctDates[0] + 'T00:00:00Z');
  const d2 = new Date(distinctDates[1] + 'T00:00:00Z');
  const d3 = new Date(distinctDates[2] + 'T00:00:00Z');
  const oneDayMs = 24 * 60 * 60 * 1000;
  const areConsecutive = (d2 - d1 === oneDayMs) && (d3 - d2 === oneDayMs);

  if (areConsecutive) {
    function hasMorningSlot(dateKey) {
      return slots.some(s => {
        if (!s.date) return false;
        const sd = new Date(s.date);
        const key = dateOnlyKey(sd.toISOString());
        return key === dateKey && s.period === 'morning' && s.isAvailable === true;
      });
    }

    const allMorningAvailable = hasMorningSlot(distinctDates[0]) && hasMorningSlot(distinctDates[1]) && hasMorningSlot(distinctDates[2]);
    cp2Passed = allMorningAvailable;
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.5 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
